AUDIT (
  name audit_drug_order_catalog_coverage,
  dialect mysql
);

-- Every source obs promoted to drug_order must have a matching child row whose
-- drug_inventory_id points at the deterministic concept-level drug catalog row
-- generated by stg_drug (drug_id = 300000 + source_value_coded).
-- Emits failing source obs rows; zero rows on pass.

WITH promoted_sources AS (
  SELECT
    s.obs_id,
    s.source_value_coded,
    300000 + s.source_value_coded AS expected_drug_id
  FROM refapp_28_demo.stg_obs s
  JOIN legacy_27_raw.concept c
    ON c.concept_id = s.source_value_coded
  JOIN legacy_27_raw.concept_class cc
    ON cc.concept_class_id = c.class_id
  WHERE cc.name = 'Drug'
)
SELECT
  ps.obs_id,
  ps.source_value_coded,
  ps.expected_drug_id,
  d.drug_inventory_id
FROM promoted_sources ps
LEFT JOIN @this_model d
  ON d.order_id = ps.obs_id
LEFT JOIN refapp_28_demo.stg_drug drg
  ON drg.drug_id = d.drug_inventory_id
WHERE d.order_id IS NULL
   OR d.drug_inventory_id IS NULL
   OR d.drug_inventory_id <> ps.expected_drug_id
   OR drg.drug_id IS NULL
;
